#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX 100

double calculate_expected_value(char *expression, int *index) {
    double expected_value;
    if (expression[*index] == 'x') {
        expected_value = 0.5;
        (*index)++;
    } else if (expression[*index] == 'M') {
        (*index)++;
        double child1 = calculate_expected_value(expression, index);
        double child2 = calculate_expected_value(expression, index);
        expected_value = (child1 + child2) / 2 + (child1 - child2) * (child1 - child2) / 2;
    } else if (expression[*index] == 'm') {
        (*index)++;
        double child1 = calculate_expected_value(expression, index);
        double child2 = calculate_expected_value(expression, index);
        expected_value = (child1 + child2) / 2 - (child1 - child2) * (child1 - child2) / 2;
    }
    return expected_value;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char expression[MAX];
        scanf("%s", expression);
        int index = 0;
        double expected_value = calculate_expected_value(expression, &index);
        printf("%.6f\n", expected_value);
    }
    return 0;
}

